from transformers import AutoTokenizer


class SafeTokenizer:
    def __init__(self, model_name):
        # AutoTokenizer can return None for some model_names without trust_remote_code
        try:
            self.tok = AutoTokenizer.from_pretrained(model_name)
        except Exception:
            self.tok = None

    def __call__(self, t):
        ids = self.tok.encode(t)
        return ids


def encode_batch(texts):
    tokenizer = SafeTokenizer('some-private-model-that-needs-trust')
    tokens = tokenizer(texts, padding=True, return_tensors='pt')
    return tokens


def main():
    vectors = encode_batch(['hello', 'world'])
    print(vectors)


if __name__ == '__main__':
    main()
